var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"다시 소개할게. 나는 제시카, 그리고 이쪽은 우리 소대원인 오르카.","JPN":"改めて紹介するわね。私はジェシカ、そしてこちらはうちの小隊員のオルカ。","ENG":"Let us introduce ourselves again. I'm Jessica, and this here is Orca. She's in my squad.","TWN":"我再介紹一次，我是潔西卡，這位是我們的小隊員 奧爾卡。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……오르카야. 반가워.","JPN":"……オルカ。よろしく。","ENG":"…I'm Orca. Nice to meet you.","TWN":"……我是奧爾卡，你好。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"반갑습니다. 휴먼. 호라이즌입니다.","JPN":"はじめまして、ヒューマン。ホライズンです。","ENG":"Pleasure to make your acquaintance as well, humans. I am Horizon.","TWN":"人類，你們好，我是地平線。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 조우했던 오르카란 휴먼과 동일한 물품을 소지하고 계시는군요.","JPN":"私が以前遭遇したオルカというヒューマンと同じ物を所持していますね。","ENG":"I see you are in possession of the same object held by another human called Orca I once encountered.","TWN":"我也遇過一位叫奧爾卡的人，你們有一樣的東西呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동명이인이거나 친족 관계십니까?","JPN":"同名異人もしくは親族関係ですか？","ENG":"Any family relation? Or purely a coincidence?","TWN":"是同名同姓，還是你們有親戚關係？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 그렇게 이해해 준다면 설명할 수고는 덜 수 있겠지.","JPN":"まあ、そう理解してくれたら説明する手間が省けて助かるわね。","ENG":"Well, something like that. If it helps us save the trouble of explaining this long story.","TWN":"嗯，就當是那樣吧，這樣就不用再浪費口水多做解釋。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"관리국을 통해 태스크포스들에 공고가 내려왔어. 널 국제 수배한다는 내용이야.","JPN":"管理局を通じてタスクフォースカンパニーに通達が出ているわ。あんたを国際手配するという内容よ。","ENG":"The Administration has put out a notice to the TASKFORCEs. There's a Red Notice out for you.","TWN":"我們收到管理局針對特遣勢力發出的公告，內容是你現在是國際通緝犯。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"최근에 관리국이 개입할 만한 사건은 일으키지 않았습니다만.","JPN":"最近になって管理局が介入するような事件を起こした覚えはありませんが。","ENG":"I don't recall committing any offense recently that would warrant the Administration's involvement.","TWN":"我最近應該沒有做什麼需要管理局介入的事情。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"의료 지원을 왔던 사람들을 학살한 유력 용의자라던데? 뭐 짚이는 거 없어?","JPN":"医療支援に来た人たちを虐殺した最有力容疑者と聞いたわよ？　何か心当たりは？","ENG":"They say you're a prime suspect behind the massacre of medical aid workers. Got any hunches on what that's about?","TWN":"有人殘忍殺害來這裡義診的人，而你是嫌犯的可能性最大？你有想到什麼嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"학살?","JPN":"虐殺？","ENG":"Massacre?","TWN":"殘忍殺害？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"수술 중인 휴먼을 공격했기에 부상을 입히기는 했지만, 생명에 지장은 없었습니다.","JPN":"今手術中のヒューマンを攻撃していたので怪我をさせたのは事実ですが、命に別状はないはずです。","ENG":"It is true I injured them for attacking the human currently under surgery, but none of the injuries were fatal.","TWN":"因為他們攻擊目前正在手術中的人類，我才會傷害他們，但不至於要他們的性命。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"상황이 종결된 뒤 나타난 자가 벌인 짓입니다.","JPN":"状況が収束した後に現れた者の仕業です。","ENG":"Someone else appeared after the situation came under control. That's the true killer.","TWN":"這是在我之後出現的人做的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"네가 방금 한 말, 증명할 방법은 있어?","JPN":"あんたの今の言葉、証明できる方法はあるの？","ENG":"Is there a way to prove what you just said?","TWN":"有證據可以證明你剛才說的話嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 기억회로를 증거로 제출하면 됩니다.","JPN":"私の記憶回路を証拠として提出するだけの話です。","ENG":"I can submit my memory data as evidence.","TWN":"我的記憶迴路可以提交作為證據。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"글쎄, 범인으로 의심 받는 상황에 사람들이 순순히 믿어 줄까?","JPN":"どうかしら、犯人と疑われる立場なのに、それで信じてもらえるかしら。","ENG":"I don't know… Will people take your word for it when you're already the prime suspect?","TWN":"不好說，在懷疑你是嫌犯的情況下，大家可能不會乖乖地相信？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"요점은 이거야. 상황이 꼬이는 바람에 우리 회사도 널 직접적으로 도와 주진 못해.","JPN":"要するに、状況がこじれたせいでうちの会社もあんたを堂々と助けることはできなくなったの。","ENG":"Let me cut to the chase. Due to this recent… complication, our company can't help you directly anymore.","TWN":"重點是，因為情況有點複雜，我們公司也無法明目張膽地幫你。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};